为了让你直观理解 PoW 的工作原理，我编写了一个简化版的 C 语言程序。

这个程序模拟了“挖矿”的过程：**寻找一个随机数（Nonce），使得区块哈希值的开头包含特定数量的零。**

### C 语言实现代码

```c
#include <stdio.h>
#include <string.h>
#include <time.h>

// 模拟一个简单的哈希函数 (实际应用中使用 SHA-256)
// 为了演示方便，我们使用一个简单的算法来模拟哈希效果
unsigned long simple_hash(const char *input) {
    unsigned long hash = 5381;
    int c;
    while ((c = *input++)) {
        hash = ((hash << 5) + hash) + c; // hash * 33 + c
    }
    return hash;
}

/**
 * PoW 核心函数
 * @param block_data 块中的数据（如交易记录）
 * @param difficulty 难度系数（要求哈希值前多少位为0）
 * @param nonce 输出的随机数
 * @return 找到满足条件的哈希值
 */
unsigned long mine(const char *block_data, int difficulty, unsigned long *nonce) {
    char input_buffer[256];
    unsigned long hash_result = 0;

    // 计算难度阈值：例如难度为2，则要求哈希值必须小于 100^2 (简化逻辑)
    // 在实际中，是要求哈希值的前 N 位是 0
    unsigned long target = 1;
    for(int i = 0; i < difficulty; i++) target *= 10;

    printf("开始挖矿... 目标难度: %d (哈希值需小于 %ld)\n", difficulty, target);

    clock_t start = clock();

    while (1) {
        // 1. 将数据和当前的 nonce 拼接
        sprintf(input_buffer, "%s%lu", block_data, *nonce);

        // 2. 计算哈希
        hash_result = simple_hash(input_buffer);

        // 3. 检查是否满足难度条件 (哈希值 < 目标值)
        if (hash_result < target) {
            break; 
        }

        // 4. 如果不满足，增加 nonce 并继续尝试
        (*nonce)++;

        // 防止死循环，如果 nonce 过大可以重置（实际中 nonce 会很大）
        if (*nonce == c_long_max_value_placeholder) { /* 逻辑处理 */ }
    }

    clock_t end = clock();
    double time_taken = ((double)(end - start)) / CLOCKS_PER_SEC;

    printf("成功挖到矿！\n");
    printf("使用的 Nonce: %lu\n", *nonce);
    printf("最终哈希值: %lu\n", hash_result);
    printf("耗时: %f 秒\n", time_taken);

    return hash_result;
}

int main() {
    // 模拟区块中的数据
    const char *block_data = "Transaction: Alice pays Bob 10 BTC";

    // 难度设置
    // 难度越高，target 越小，寻找过程越难
    int difficulty = 6; 

    unsigned long nonce = 0;

    // 执行挖矿
    mine(block_data, difficulty, &nonce);

    return 0;
}
```

---

### 代码详细解释

#### 1. 模拟哈希函数 (`simple_hash`)
在真实的比特币中，使用的是 **SHA-256** 算法。为了让代码能直接运行且不依赖复杂的库，我实现了一个基于 `djb2` 算法的简化版哈希函数。它能将字符串转换为一个巨大的数字。

